/**************************************************************************
 * IMPORTS
 ***************************************************************************/
import { CrispClass as Crisp } from "./index";
/**************************************************************************
 * ENUMERATIONS
 ***************************************************************************/
export declare enum EventsColors {
    Red = "red",
    Orange = "orange",
    Yellow = "yellow",
    Green = "green",
    Blue = "blue",
    Purple = "purple",
    Pink = "pink",
    Brown = "brown",
    Grey = "grey",
    Black = "black"
}
/**************************************************************************
 * CLASS
 ***************************************************************************/
/**
 * Crisp session management
 */
export default class CrispSession {
    private parent;
    /**
     * Constructor
     */
    constructor(crisp: Crisp);
    /**
     * Resets the current session
     */
    reset(reload?: boolean): void;
    /**
     * Sets session segments
     */
    setSegments(segments: string[], overwrite?: boolean): void;
    /**
     * Sets session data
     */
    setData(data: object): void;
    /**
     * Pushes an event to the session
     */
    pushEvent(name: string, data?: object, color?: EventsColors): void;
    /**
     * Gets session data by key
     */
    getData(key: string): string | boolean | number | undefined;
    /**
     * Gets the session identifier
     */
    getIdentifier(): string | null;
    /**
     * Registers a callback for session loaded event
     */
    onLoaded(callback: Function): void;
    /**
     * Unregisters the session loaded callback
     */
    offLoaded(): void;
    /**
     * Checks if a value is valid for session data
     */
    private isValidDataValue;
}
